.site-nav {
    display: flex;
    gap: 0.75rem;
    margin-right: 1.5rem;
    align-items: center;
    position: relative;
    top: 2px;
}

/* Hamburger toggle: desktop-hidden, revealed only at mobile widths.
   Scoped to .header-controls so it outranks the later `.header-icon`
   display rule the button also carries. */
.header-controls .nav-toggle {
    display: none;
    background: none;
    border: none;
    cursor: pointer;
    padding: 0;
}
.nav-toggle .nav-toggle-close { display: none; }
.site-header.nav-open .nav-toggle .nav-toggle-open { display: none; }
.site-header.nav-open .nav-toggle .nav-toggle-close { display: block; }

/* APG Disclosure Navigation (#645): a row of 3 section heads, each a real
   <button> disclosing its own absolutely-positioned panel below it. Opening a
   panel never resizes the header. Baseline reveal is CSS (:hover/:focus-within);
   reveal-nav.js layers aria-expanded toggling + Esc/outside-click on top.
   (Mobile renders the sections as an inline accordion — see the media query.) */
.nav-menu {
    display: flex;
    gap: 0.25rem;
}
.nav-menu-section {
    position: relative;
}

/* The head button (reset native button chrome, keep the original look). */
.nav-menu-head {
    background: none;
    border: none;
    cursor: pointer;
    font-family: inherit;
    padding: 0.3rem 0.6rem;
    font-size: 0.9em;
    font-weight: 500;
    color: var(--color-text-muted);
    text-align: left;
    white-space: nowrap;
    border-radius: 6px;
    transition: color 0.2s ease, background 0.2s ease;
}
.nav-menu-section:hover .nav-menu-head,
.nav-menu-section:focus-within .nav-menu-head,
.nav-menu-head[aria-expanded="true"] {
    color: var(--color-text-main);
}
.nav-menu-head:focus-visible {
    outline: 2px solid var(--color-primary);
    outline-offset: 2px;
}

/* The disclosed panel, anchored under its own head. The ::before bridges the
   margin gap so a hover survives the trip from head to panel. */
.nav-menu-panel {
    position: absolute;
    top: 100%;
    left: 0;
    z-index: 50;
    min-width: 11rem;
    box-sizing: border-box;
    padding: 0.5rem;
    margin-top: 8px;
    background: rgba(255, 255, 255, 0.98);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border: 1px solid var(--color-border, #e2e8f0);
    border-radius: 12px;
    box-shadow: 0 12px 32px -8px rgba(15, 23, 42, 0.18), 0 2px 8px -2px rgba(15, 23, 42, 0.08);
    opacity: 0;
    visibility: hidden;
    transform: translateY(-6px);
    transition: opacity 0.28s ease, transform 0.28s ease, visibility 0.28s;
}
.nav-menu-panel::before {
    content: "";
    position: absolute;
    top: -8px;
    left: 0;
    right: 0;
    height: 8px;
}
/* Reveal triggers:
   - :hover — pointer sugar, always on (a mouse user peeks a panel; click pins it).
   - :focus-within — the keyboard baseline #645 requires, but ONLY without JS.
     Under JS (reveal-nav.js sets .js-nav) the keyboard path becomes
     aria-expanded-driven so Esc / outside-click can collapse a panel even while
     focus is still inside it — something :focus-within alone can't express.
   - [aria-expanded="true"] — the explicit disclosure state the button toggles. */
.nav-menu-section:hover .nav-menu-panel,
html:not(.js-nav) .nav-menu-section:focus-within .nav-menu-panel,
.nav-menu-head[aria-expanded="true"] + .nav-menu-panel {
    opacity: 1;
    visibility: visible;
    transform: translateY(0);
}
@media (prefers-reduced-motion: reduce) {
    .nav-menu-panel {
        transition: opacity 0.28s ease, visibility 0.28s;
        transform: none;
    }
    .nav-menu-section:hover .nav-menu-panel,
    html:not(.js-nav) .nav-menu-section:focus-within .nav-menu-panel,
    .nav-menu-head[aria-expanded="true"] + .nav-menu-panel {
        transform: none;
    }
}

/* Each column in the popup. The in-panel label is redundant on desktop (the
   head above stands in), so it's hidden here and revealed only on mobile. */
.nav-menu-panel .nav-group {
    flex: 1 1 0;
    min-width: 7.5rem;
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}
.nav-menu-panel .nav-group-label {
    display: none;
}
.nav-group-links {
    display: flex;
    flex-direction: column;
    align-items: stretch;
    gap: 0.1rem;
}
.nav-group-links .nav-link {
    padding: 0.35rem 0.6rem;
    border-radius: 5px;
    white-space: nowrap;
    transition: opacity 0.2s ease, color 0.2s ease, background 0.2s ease;
}
.nav-group-links .nav-link:hover {
    background: rgba(0, 0, 0, 0.04);
}

.nav-link {
    color: inherit;
    text-decoration: none;
    font-size: 0.9em;
    font-weight: 500;
    opacity: 0.8;
    transition: opacity 0.2s ease, color 0.2s ease;
}

.nav-link:hover {
    opacity: 1;
    color: var(--color-primary);
}

/* ── Mobile nav: collapse the grouped nav into a hamburger dropdown.
   Desktop (>860px) is untouched — the toggle stays hidden and the inline
   nav renders exactly as before. ── */
@media (max-width: 940px) {
    .header-controls .nav-toggle {
        display: flex;
        align-items: center;
        color: var(--color-text-muted);
    }
    .nav-toggle:hover {
        color: var(--color-primary);
    }

    .site-nav {
        position: absolute;
        top: 100%;
        left: 0;
        right: 0;
        flex-direction: column;
        align-items: stretch;
        gap: 0.5rem;
        margin: 0;
        padding: var(--spacing-sm) var(--spacing-md);
        background: rgba(255, 255, 255, 0.96);
        backdrop-filter: blur(12px);
        -webkit-backdrop-filter: blur(12px);
        border-bottom: 1px solid var(--color-border);
        box-shadow: var(--shadow-md);
        max-height: calc(100vh - var(--header-height, 57px));
        overflow-y: auto;
        display: none;
    }
    .site-header.nav-open .site-nav {
        display: flex;
    }

    /* The whole nav is already a hamburger dropdown here, so collapse the
       disclosure machinery: stack the sections, turn each head button into an
       inline section header, and render every panel inline (the hamburger itself
       is the outer disclosure). */
    .nav-menu {
        width: 100%;
        flex-direction: column;
        gap: 0.5rem;
    }
    .nav-menu-section {
        width: 100%;
    }
    /* The head button becomes the inline section header (it stands in for the
       in-panel group label, which stays hidden). */
    .nav-menu-head {
        display: block;
        width: 100%;
        font-size: 0.65em;
        text-transform: uppercase;
        letter-spacing: 0.07em;
        font-weight: 600;
        color: var(--color-text-muted);
        opacity: 0.55;
        padding: 0.15rem 0.7rem 0.25rem;
    }
    .nav-menu-panel {
        position: static;
        display: flex;
        flex-direction: column;
        gap: 0.5rem;
        padding: 0;
        margin: 0;
        background: none;
        border: none;
        border-radius: 0;
        box-shadow: none;
        backdrop-filter: none;
        -webkit-backdrop-filter: none;
        opacity: 1;
        visibility: visible;
        transform: none;
    }
    .nav-menu-panel::before {
        display: none;
    }

    .nav-group {
        width: 100%;
        box-sizing: border-box;
        padding: 0.25rem 0.7rem;
        border: 1px solid var(--color-border, #e2e8f0);
        border-radius: 8px;
        background: rgba(0, 0, 0, 0.015);
    }
    /* The head button is the section header on mobile, so the in-panel label
       stays redundant and hidden. */
    .nav-menu-panel .nav-group-label {
        display: none;
    }
    .nav-group-links {
        flex-direction: row;
        flex-wrap: wrap;
        gap: 1rem 1.25rem;
    }
    /* Larger tap targets on touch screens. */
    .nav-group-links .nav-link {
        padding: 0.25rem 0;
        font-size: 1em;
    }
}

.header-icon {
    color: var(--color-text-muted);
    transition: color 0.2s ease;
    flex-shrink: 0;
    display: flex;
    align-items: center;
}

/* reveal-nav.js — progressive enhancement for the W3C APG Disclosure Navigation
 * header (#645, the conform-to reference for #644).
 *
 * The CSS baseline (no JS) reveals each section's panel on :hover / :focus-within.
 * This script adds the APG semantics on top:
 *   - sets `.js-nav` on <html>, which drops the :focus-within reveal in favour of
 *     an aria-expanded-driven one, so Esc / outside-click can collapse a panel
 *     even while focus is still inside it (which :focus-within can't express).
 *     Pointer :hover stays as CSS sugar — a mouse user peeks a panel; a click pins it;
 *   - each head button is a real toggle: click / Enter / Space flips aria-expanded
 *     (opening one closes its siblings);
 *   - Escape closes the open section and returns focus to its head button;
 *   - clicking or moving focus outside the nav dismisses any open panel.
 *
 * Desktop only: below the mobile breakpoint the sections render as an inline
 * accordion (panels are CSS-static), so toggling is a no-op there.
 */
(function () {
  'use strict';
  var nav = document.getElementById('site-nav');
  if (!nav) return;
  var sections = Array.prototype.slice.call(nav.querySelectorAll('.nav-menu-section'));
  if (!sections.length) return;

  // Cut the mustard: hand the keyboard reveal to aria-expanded (see the CSS).
  document.documentElement.classList.add('js-nav');

  var isDesktop = function () { return window.matchMedia('(min-width: 941px)').matches; };
  var headOf = function (s) { return s.querySelector('.nav-menu-head'); };
  var isOpen = function (s) {
    var b = headOf(s);
    return !!b && b.getAttribute('aria-expanded') === 'true';
  };
  var setOpen = function (s, open) {
    var b = headOf(s);
    if (b) b.setAttribute('aria-expanded', open ? 'true' : 'false');
  };
  var closeAll = function (except) {
    sections.forEach(function (s) { if (s !== except) setOpen(s, false); });
  };

  sections.forEach(function (s) {
    var btn = headOf(s);
    if (!btn) return;
    // Click / Enter / Space is the canonical disclosure control (a button gives
    // Enter + Space activation natively).
    btn.addEventListener('click', function () {
      if (!isDesktop()) return;          // mobile panels are inline/static
      var open = isOpen(s);
      closeAll(s);
      setOpen(s, !open);
    });
  });

  // Escape closes the open section and returns focus to its head.
  nav.addEventListener('keydown', function (e) {
    if (e.key !== 'Escape') return;
    var open = sections.filter(isOpen)[0];
    if (open) {
      setOpen(open, false);
      var b = headOf(open);
      if (b) b.focus();
    }
  });

  // Clicking or moving focus outside the nav dismisses everything.
  document.addEventListener('click', function (e) {
    if (!nav.contains(e.target)) closeAll(null);
  });
  document.addEventListener('focusin', function (e) {
    if (!nav.contains(e.target)) closeAll(null);
  });
  // Crossing into the mobile layout: clear any open desktop state.
  window.addEventListener('resize', function () {
    if (!isDesktop()) closeAll(null);
  });
})();

.cmdk-trigger {
  display: inline-flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.4rem 0.7rem;
  font: inherit;
  color: var(--color-text-muted);
  background: rgba(0, 0, 0, 0.03);
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 8px;
  cursor: pointer;
}
.cmdk-trigger-kbd {
  font-size: 0.75em;
  padding: 0.05rem 0.35rem;
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 4px;
  background: #fff;
}
.cmdk::backdrop {
  background: rgba(15, 23, 42, 0.35);
  backdrop-filter: blur(2px);
}
.cmdk {
  width: min(36rem, 92vw);
  padding: 0;
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 14px;
  box-shadow: 0 24px 60px -16px rgba(15, 23, 42, 0.4);
}
.cmdk-box { padding: 0.6rem; }
.cmdk-input {
  width: 100%;
  box-sizing: border-box;
  padding: 0.6rem 0.7rem;
  font-size: 1rem;
  border: none;
  border-bottom: 1px solid var(--color-border, #e2e8f0);
  outline: none;
}
.cmdk-list {
  list-style: none;
  margin: 0.4rem 0 0;
  padding: 0;
  max-height: 18rem;
  overflow-y: auto;
}
.cmdk-option {
  padding: 0.5rem 0.7rem;
  border-radius: 8px;
  cursor: pointer;
}
.cmdk-option[aria-selected="true"],
.cmdk-option:hover {
  background: rgba(0, 0, 0, 0.05);
}
.cmdk-empty {
  padding: 0.7rem;
  color: var(--color-text-muted);
}
@media (prefers-reduced-motion: reduce) {
  .cmdk::backdrop { backdrop-filter: none; }
}

/* command-palette.js (#856) — progressive enhancement for the ⌘K command
 * palette. Baseline markup is a native <dialog> + filterable listbox; this
 * layers the global shortcut, incremental filtering, and roving keyboard
 * selection via aria-activedescendant.
 */
(function () {
  'use strict';
  var dialog = document.getElementById('cmdk');
  if (!dialog || typeof dialog.showModal !== 'function') return;
  var input = dialog.querySelector('[data-cmdk-input]');
  var list = dialog.querySelector('#cmdk-list');
  var empty = dialog.querySelector('.cmdk-empty');
  var triggers = document.querySelectorAll('[data-cmdk-open]');
  var options = function () {
    return Array.prototype.slice.call(list.querySelectorAll('.cmdk-option')).filter(function (o) {
      return !o.hidden;
    });
  };

  var open = function () { if (!dialog.open) { dialog.showModal(); input.value = ''; filter(''); input.focus(); } };
  Array.prototype.forEach.call(triggers, function (t) { t.addEventListener('click', open); });
  document.addEventListener('keydown', function (e) {
    if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === 'k') { e.preventDefault(); open(); }
  });

  var highlight = function (opt) {
    options().forEach(function (o) { o.setAttribute('aria-selected', o === opt ? 'true' : 'false'); });
    if (opt) { input.setAttribute('aria-activedescendant', opt.id); opt.scrollIntoView({ block: 'nearest' }); }
  };
  var filter = function (q) {
    q = q.trim().toLowerCase();
    var any = false;
    Array.prototype.forEach.call(list.querySelectorAll('.cmdk-option'), function (o) {
      var match = o.dataset.value.toLowerCase().indexOf(q) !== -1;
      o.hidden = !match;
      any = any || match;
    });
    if (empty) empty.hidden = any;
    highlight(options()[0] || null);
  };
  input.addEventListener('input', function () { filter(input.value); });

  input.addEventListener('keydown', function (e) {
    var opts = options();
    if (!opts.length) return;
    var cur = opts.indexOf(opts.filter(function (o) { return o.getAttribute('aria-selected') === 'true'; })[0]);
    if (e.key === 'ArrowDown') { e.preventDefault(); highlight(opts[Math.min(cur + 1, opts.length - 1)]); }
    else if (e.key === 'ArrowUp') { e.preventDefault(); highlight(opts[Math.max(cur - 1, 0)]); }
    else if (e.key === 'Enter') {
      e.preventDefault();
      var sel = opts[cur] || opts[0];
      if (sel) { dialog.close(); dialog.dispatchEvent(new CustomEvent('cmdk:select', { detail: { value: sel.dataset.value } })); }
    }
  });

  list.addEventListener('click', function (e) {
    var opt = e.target.closest('.cmdk-option');
    if (!opt) return;
    dialog.close();
    dialog.dispatchEvent(new CustomEvent('cmdk:select', { detail: { value: opt.dataset.value } }));
  });
})();

.filter-bar {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-end;
  gap: 1rem;
  padding: 0.75rem 1rem;
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 12px;
  background: rgba(0, 0, 0, 0.015);
}
.filter-field { display: flex; flex-direction: column; gap: 0.25rem; }
.filter-label {
  font-size: 0.7em;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--color-text-muted);
}
.filter-input,
.filter-select {
  padding: 0.4rem 0.6rem;
  font: inherit;
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 8px;
}
.filter-field[role="radiogroup"] {
  flex-direction: row;
  align-items: center;
  gap: 0;
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 8px;
  overflow: hidden;
}
.filter-seg {
  display: inline-flex;
  align-items: center;
  gap: 0.3rem;
  padding: 0.4rem 0.7rem;
  cursor: pointer;
  font-size: 0.9em;
}
.filter-seg:has(input:checked) {
  background: var(--color-primary, #2563eb);
  color: #fff;
}
.filter-seg input { position: absolute; opacity: 0; pointer-events: none; }
.filter-count {
  margin-left: auto;
  align-self: center;
  font-size: 0.85em;
  color: var(--color-text-muted);
}
.filter-clear {
  align-self: center;
  padding: 0.4rem 0.8rem;
  font: inherit;
  background: none;
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 8px;
  cursor: pointer;
}

/* filter-bar.js (#857) — progressive enhancement for the filter bar. Baseline
 * markup is real form controls; this debounces text input and emits a single
 * normalized "filter:change" CustomEvent carrying the current filter state, so
 * a consumer wires one listener instead of N control handlers.
 */
(function () {
  'use strict';
  var bar = document.querySelector('[data-filter-bar]');
  if (!bar) return;
  var countEl = bar.querySelector('[data-filter-count]');

  var readState = function () {
    var state = {};
    Array.prototype.forEach.call(bar.querySelectorAll('[data-filter]'), function (el) {
      var key = el.dataset.filter;
      if (el.type === 'radio') { if (el.checked) state[key] = el.value; }
      else if (el.multiple) {
        state[key] = Array.prototype.filter.call(el.options, function (o) { return o.selected; }).map(function (o) { return o.value; });
      } else { state[key] = el.value; }
    });
    return state;
  };

  var emit = function () {
    bar.dispatchEvent(new CustomEvent('filter:change', { bubbles: true, detail: readState() }));
  };

  var timer = null;
  bar.addEventListener('input', function (e) {
    if (e.target.type === 'search' || e.target.type === 'text') {
      clearTimeout(timer);
      timer = setTimeout(emit, 180);
    } else { emit(); }
  });
  bar.addEventListener('change', function (e) {
    if (e.target.type !== 'search' && e.target.type !== 'text') emit();
  });
  bar.addEventListener('reset', function () { setTimeout(emit, 0); });

  // Public helper: a consumer calls bar.setResultCount(n) to reflect a live total.
  bar.setResultCount = function (n) {
    if (countEl) countEl.textContent = n + (n === 1 ? ' result' : ' results');
  };
})();

.hovercard { position: relative; display: inline-block; }
.hovercard-trigger {
  color: var(--color-primary, #2563eb);
  text-decoration: none;
  font-weight: 500;
}
.hovercard-trigger:hover { text-decoration: underline; }
.hovercard-card {
  position: absolute;
  top: calc(100% + 8px);
  left: 0;
  z-index: 60;
  width: 18rem;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  padding: 0.8rem;
  background: #fff;
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 12px;
  box-shadow: 0 16px 40px -12px rgba(15, 23, 42, 0.25);
  opacity: 0;
  transform: translateY(-4px);
  transition: opacity 0.2s ease, transform 0.2s ease;
}
.hovercard-card:not([hidden]) { opacity: 1; transform: translateY(0); }
.hovercard-head { display: flex; gap: 0.6rem; align-items: center; }
.hovercard-avatar { border-radius: 50%; flex-shrink: 0; }
.hovercard-id { display: flex; flex-direction: column; }
.hovercard-handle { color: var(--color-text-muted); font-size: 0.85em; }
.hovercard-bio { font-size: 0.9em; color: var(--color-text-main); }
@media (prefers-reduced-motion: reduce) {
  .hovercard-card { transition: opacity 0.2s ease; transform: none; }
  .hovercard-card:not([hidden]) { transform: none; }
}

/* hovercard.js (#858) — progressive enhancement for the hovercard. Baseline
 * markup is a trigger + a hidden card region (the [hidden] attribute keeps it
 * out of the a11y tree until shown). This layers hover-intent open/close delays
 * so a quick pass-through doesn't flash the card, plus focus/blur support and
 * Esc-to-dismiss for keyboard users.
 */
(function () {
  'use strict';
  Array.prototype.forEach.call(document.querySelectorAll('[data-hovercard]'), function (root) {
    var trigger = root.querySelector('[data-hovercard-trigger]');
    var card = root.querySelector('[data-hovercard-card]');
    if (!trigger || !card) return;
    var openDelay = parseInt(root.dataset.openDelay, 10) || 350;
    var closeDelay = 200;
    var openT = null, closeT = null;

    var show = function () {
      clearTimeout(closeT);
      openT = setTimeout(function () { card.hidden = false; }, openDelay);
    };
    var hide = function () {
      clearTimeout(openT);
      closeT = setTimeout(function () { card.hidden = true; }, closeDelay);
    };

    trigger.addEventListener('mouseenter', show);
    trigger.addEventListener('mouseleave', hide);
    card.addEventListener('mouseenter', function () { clearTimeout(closeT); });
    card.addEventListener('mouseleave', hide);

    // Keyboard: focus opens immediately, blur (focus leaving the root) closes.
    trigger.addEventListener('focus', function () { clearTimeout(closeT); card.hidden = false; });
    root.addEventListener('focusout', function (e) {
      if (!root.contains(e.relatedTarget)) card.hidden = true;
    });
    trigger.addEventListener('keydown', function (e) {
      if (e.key === 'Escape' && !card.hidden) { card.hidden = true; }
    });
  });
})();

.toolbar {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.3rem;
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 10px;
  background: rgba(0, 0, 0, 0.015);
}
.toolbar-group { display: inline-flex; gap: 0.15rem; }
.toolbar-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 2rem;
  height: 2rem;
  padding: 0 0.5rem;
  font: inherit;
  color: var(--color-text-main);
  background: none;
  border: 1px solid transparent;
  border-radius: 7px;
  cursor: pointer;
}
.toolbar-btn:hover { background: rgba(0, 0, 0, 0.05); }
.toolbar-btn:focus-visible {
  outline: 2px solid var(--color-primary, #2563eb);
  outline-offset: 1px;
}
.toolbar-btn[aria-pressed="true"] {
  background: var(--color-primary, #2563eb);
  color: #fff;
}
.toolbar-sep {
  width: 1px;
  align-self: stretch;
  margin: 0.2rem 0.15rem;
  background: var(--color-border, #e2e8f0);
}

/* toolbar.js (#859) — progressive enhancement for the W3C APG toolbar. Baseline
 * markup already keeps the toolbar to one Tab stop (first button tabindex=0, the
 * rest -1). This layers the roving-tabindex behaviour: Arrow keys move focus and
 * the tab stop between controls, Home/End jump to the ends, and toggle buttons
 * flip aria-pressed on activation.
 */
(function () {
  'use strict';
  Array.prototype.forEach.call(document.querySelectorAll('[data-toolbar]'), function (toolbar) {
    var vertical = toolbar.getAttribute('aria-orientation') === 'vertical';
    var items = function () {
      return Array.prototype.slice.call(toolbar.querySelectorAll('.toolbar-btn'));
    };
    var focusAt = function (list, i) {
      var n = (i + list.length) % list.length;
      list.forEach(function (b, j) { b.tabIndex = j === n ? 0 : -1; });
      list[n].focus();
    };

    toolbar.addEventListener('keydown', function (e) {
      var list = items();
      var i = list.indexOf(document.activeElement);
      if (i === -1) return;
      var next = vertical ? 'ArrowDown' : 'ArrowRight';
      var prev = vertical ? 'ArrowUp' : 'ArrowLeft';
      if (e.key === next) { e.preventDefault(); focusAt(list, i + 1); }
      else if (e.key === prev) { e.preventDefault(); focusAt(list, i - 1); }
      else if (e.key === 'Home') { e.preventDefault(); focusAt(list, 0); }
      else if (e.key === 'End') { e.preventDefault(); focusAt(list, list.length - 1); }
    });

    // Toggle buttons flip aria-pressed on click.
    toolbar.addEventListener('click', function (e) {
      var btn = e.target.closest('.toolbar-btn');
      if (btn && btn.hasAttribute('aria-pressed')) {
        btn.setAttribute('aria-pressed', btn.getAttribute('aria-pressed') === 'true' ? 'false' : 'true');
      }
    });
  });
})();
